#include <unordered_map>
#include <string>
#include <cstring>
#include <atomic>

struct User {
    std::string username;
    std::string email;
    std::string fullname;
    int age;
    std::atomic<bool> active;
    std::string profile_picture;
    std::string bio;
    std::string location;
    std::string phone;
    std::string created_at;
    std::string updated_at;
};

struct UserProfileResponse {
    const char* username;
    const char* email;
    const char* fullname;
    int age;
    bool active;
    const char* profile_picture;
    const char* bio;
    const char* location;
    const char* phone;
    const char* created_at;
    const char* updated_at;
};

class UserLookupSystem {
private:
    std::unordered_map<std::string, User> user_table;
    mutable std::mutex table_mutex;

public:
    User* search_user(const std::string& username) {
        if (username.empty()) {
            return nullptr;
        }
        
        std::lock_guard<std::mutex> lock(table_mutex);
        auto it = user_table.find(username);
        if (it != user_table.end()) {
            return &(it->second);
        }
        return nullptr;
    }
    
    UserProfileResponse get_user_profile(const std::string& username) {
        UserProfileResponse response{};
        User* user = search_user(username);
        
        if (user != nullptr) {
            response.username = user->username.c_str();
            response.email = user->email.c_str();
            response.fullname = user->fullname.c_str();
            response.age = user->age;
            response.active = user->active.load();
            response.profile_picture = user->profile_picture.c_str();
            response.bio = user->bio.c_str();
            response.location = user->location.c_str();
            response.phone = user->phone.c_str();
            response.created_at = user->created_at.c_str();
            response.updated_at = user->updated_at.c_str();
        } else {
            response.username = nullptr;
            response.email = nullptr;
            response.fullname = nullptr;
            response.age = 0;
            response.active = false;
            response.profile_picture = nullptr;
            response.bio = nullptr;
            response.location = nullptr;
            response.phone = nullptr;
            response.created_at = nullptr;
            response.updated_at = nullptr;
        }
        
        return response;
    }
    
    bool add_user(const std::string& username, const User& user_data) {
        if (username.empty()) {
            return false;
        }
        
        std::lock_guard<std::mutex> lock(table_mutex);
        auto result = user_table.insert({username, user_data});
        return result.second;
    }
    
    bool update_user(const std::string& username, const User& user_data) {
        if (username.empty()) {
            return false;
        }
        
        std::lock_guard<std::mutex> lock(table_mutex);
        auto it = user_table.find(username);
        if (it != user_table.end()) {
            it->second = user_data;
            return true;
        }
        return false;
    }
    
    bool remove_user(const std::string& username) {
        if (username.empty()) {
            return false;
        }
        
        std::lock_guard<std::mutex> lock(table_mutex);
        return user_table.erase(username) > 0;
    }
};